function demoReply(p){
  const q=p.toLowerCase()
  if(q.includes("hello")||q.includes("hi")||q.includes("namaste")) return "👋 Namaste! Main VINITRONX AI hoon — India ka #1 AI Platform! 🚀"
  if(q.includes("vinitronx")) return "⚡ VINITRONX AI — Build. Earn. Automate with AI. Maharashtra se poori duniya mein! 🌍"
  if(q.includes("vinit")||q.includes("who")) return "👨‍💻 Banaya hai Vinit Vijay Bhadke ne — passionate AI developer, freelancer aur VINITRONX ka founder!"
  if(q.includes("feature")||q.includes("kya")) return "🛠️ Claude AI, Gemini, Demo mode, lightning fast, secure, mobile-ready — sab kuch ek jagah!"
  if(q.includes("price")||q.includes("cost")||q.includes("free")) return "💰 Demo mode bilkul FREE hai! Claude mode ke liye apni Anthropic API key chahiye — console.anthropic.com se lo."
  return `🎮 Demo: "${p}" — Real Claude AI ke liye Claude mode select karo! 💡`
}

