// ── PAGE 2: CHAT ────────────────────────────────────────────
function Chat(){
  const [msgs,setMsgs]=useState([{role:"ai",model:"system",content:"⚡ VINITRONX AI — Online!\n\nNamaste! Koi bhi sawaal pucho.\n🧠 Claude = Real AI  |  🎮 Demo = Free\n\nMain ready hoon! 🚀"}])
  const [input,setInput]=useState("")
  const [loading,setLoading]=useState(false)
  const [model,setModel]=useState("demo")
  const ref=useRef(null)
  useEffect(()=>{ref.current?.scrollIntoView({behavior:"smooth"})},[msgs,loading])

  const MS={
    claude:{label:"🧠 Claude",color:S.cyan,tag:"ANTHROPIC"},
    demo:{label:"🎮 Demo",color:S.green,tag:"FREE MODE"},
  }
  const cfg=MS[model]

  const send=async()=>{
    const p=input.trim(); if(!p||loading) return
    setInput(""); setLoading(true)
    setMsgs(m=>[...m,{role:"user",content:p}])
    try{
      let text=""
      if(model==="demo"){
        await new Promise(r=>setTimeout(r,700))
        text=demoReply(p)
      } else {
        const res=await fetch("https://api.anthropic.com/v1/messages",{
          method:"POST",
          headers:{"Content-Type":"application/json"},
          body:JSON.stringify({
            model:"claude-sonnet-4-20250514",max_tokens:1024,
            system:"You are VINITRONX AI, a smart assistant created by Vinit Vijay Bhadke from Maharashtra, India. Platform tagline: Build. Earn. Automate with AI. Reply in Hinglish (Hindi+English mix) unless user writes pure English. Be helpful, friendly, concise.",
            messages:[{role:"user",content:p}]
          })
        })
        const d=await res.json()
        text=d.content?.[0]?.text||"Response nahi mila. Try again!"
      }
      setMsgs(m=>[...m,{role:"ai",model,content:text}])
    }catch(e){
      setMsgs(m=>[...m,{role:"ai",model:"error",content:`❌ ${e.message}\n\n💡 Demo mode try karo!`}])
    }
    setLoading(false)
  }

  return(
    <div style={{display:"flex",flexDirection:"column",height:"calc(100vh - 62px)"}}>
      {/* Toolbar */}
      <div style={{padding:"10px 18px",display:"flex",alignItems:"center",gap:8,flexWrap:"wrap",borderBottom:`1px solid ${S.border}`,background:"rgba(2,4,8,0.75)",backdropFilter:"blur(12px)"}}>
        {Object.entries(MS).map(([k,m])=>(
          <button key={k} onClick={()=>setModel(k)} style={{background:model===k?`${m.color}16`:"transparent",border:`1px solid ${model===k?m.color:"rgba(255,255,255,0.1)"}`,color:model===k?m.color:"rgba(255,255,255,0.3)",fontFamily:"monospace",fontSize:10,letterSpacing:1,padding:"8px 18px",borderRadius:9,cursor:"pointer",boxShadow:model===k?`0 0 16px ${m.color}44`:"none",transition:"all 0.2s"}}>
            {m.label}
          </button>
        ))}
        <div style={{marginLeft:"auto",display:"flex",alignItems:"center",gap:7}}>
          <span style={{width:7,height:7,borderRadius:"50%",background:cfg.color,boxShadow:`0 0 10px ${cfg.color}`,display:"inline-block"}}/>
          <span style={{fontFamily:"monospace",fontSize:9,color:cfg.color,letterSpacing:2}}>{cfg.tag} ACTIVE</span>
        </div>
        <button onClick={()=>setMsgs([{role:"ai",model:"system",content:"🗑️ Cleared! Fresh start karo. 🚀"}])}
          style={{background:"transparent",border:"1px solid rgba(255,50,50,0.22)",color:"rgba(255,80,80,0.5)",fontFamily:"monospace",fontSize:8,padding:"5px 12px",borderRadius:6,cursor:"pointer",letterSpacing:1}}>
          CLEAR
        </button>
      </div>

      {/* Messages */}
      <div style={{flex:1,overflowY:"auto",padding:"18px 16px",display:"flex",flexDirection:"column",gap:16}}>
        {msgs.map((m,i)=>(
          <div key={i} style={{display:"flex",flexDirection:"column",alignItems:m.role==="user"?"flex-end":"flex-start",animation:"fadeUp 0.35s ease forwards"}}>
            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}>
              {m.role!=="user"&&<img src={LOGO_SRC} style={{width:24,height:24,borderRadius:"50%",objectFit:"cover",border:`1px solid ${S.border}`}} alt=""/>}
              <span style={{fontFamily:"monospace",fontSize:8,letterSpacing:2,color:m.role==="user"?"rgba(0,245,255,0.35)":"rgba(191,0,255,0.38)"}}>
                {m.role==="user"?"YOU":`VINITRONX [${(m.model||"AI").toUpperCase()}]`}
              </span>
              {m.role==="user"&&<img src={PHOTO_SRC} style={{width:24,height:24,borderRadius:"50%",objectFit:"cover",border:"1px solid rgba(0,245,255,0.4)"}} alt=""/>}
            </div>
            <div style={{maxWidth:"82%",padding:"13px 17px",fontSize:14,lineHeight:1.82,whiteSpace:"pre-wrap",wordBreak:"break-word",background:m.role==="user"?"rgba(0,245,255,0.07)":"rgba(4,12,32,0.92)",border:`1px solid ${m.role==="user"?"rgba(0,245,255,0.22)":"rgba(191,0,255,0.2)"}`,borderRadius:m.role==="user"?"14px 14px 2px 14px":"14px 14px 14px 2px",color:S.text,fontFamily:"sans-serif"}}>
              {m.content}
            </div>
          </div>
        ))}
        {loading&&(
          <div style={{display:"flex",flexDirection:"column",alignItems:"flex-start"}}>
            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}>
              <img src={LOGO_SRC} style={{width:24,height:24,borderRadius:"50%",objectFit:"cover",border:`1px solid ${S.border}`}} alt=""/>
              <span style={{fontFamily:"monospace",fontSize:8,letterSpacing:2,color:"rgba(191,0,255,0.38)"}}>VINITRONX [{model.toUpperCase()}] THINKING...</span>
            </div>
            <div style={{padding:"14px 20px",background:"rgba(4,12,32,0.92)",border:"1px solid rgba(191,0,255,0.2)",borderRadius:"14px 14px 14px 2px",display:"flex",gap:7,alignItems:"center"}}>
              {[0,160,320].map((d,i)=><span key={i} style={{width:8,height:8,borderRadius:"50%",background:S.cyan,display:"inline-block",animation:`tdot 1.2s ${d}ms infinite`}}/>)}
            </div>
          </div>
        )}
        <div ref={ref}/>
      </div>

      {/* Input */}
      <div style={{padding:"10px 16px 18px",background:"rgba(2,4,8,0.85)",backdropFilter:"blur(16px)",borderTop:`1px solid ${S.border}`}}>
        <div style={{display:"flex",gap:10,alignItems:"flex-end",background:"rgba(0,6,18,0.98)",border:`1px solid ${S.border}`,borderRadius:14,padding:"10px 14px"}}>
          <textarea rows={2} value={input}
            onChange={e=>setInput(e.target.value)}
            onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();send()}}}
            placeholder={`${cfg.tag} — sawaal likho... (Enter send, Shift+Enter new line)`}
            disabled={loading}
            style={{flex:1,background:"transparent",border:"none",outline:"none",color:S.text,fontSize:14,fontFamily:"sans-serif",resize:"none",lineHeight:1.6}}/>
          <button onClick={send} disabled={loading||!input.trim()} style={{background:(!loading&&input.trim())?"linear-gradient(135deg,#00f5ff,#bf00ff)":"rgba(255,255,255,0.04)",border:"none",color:(!loading&&input.trim())?"#000":"rgba(255,255,255,0.15)",fontFamily:"monospace",fontSize:10,fontWeight:700,letterSpacing:1.5,padding:"13px 20px",borderRadius:10,cursor:(!loading&&input.trim())?"pointer":"not-allowed",transition:"all 0.2s",whiteSpace:"nowrap"}}>
            {loading?"···":"SEND ▶"}
          </button>
        </div>
        <div style={{textAlign:"center",fontFamily:"monospace",fontSize:8,color:"rgba(0,245,255,0.18)",letterSpacing:2,marginTop:7}}>POWERED BY ANTHROPIC CLAUDE · VINITRONX AI v1.0</div>
      </div>
    </div>
  )
}

